<?php

declare(strict_types=1);

/**
 * Powermail Fluid templates for the desiderio shadcn set.
 *
 * These templates are GENERATED by Build/Scripts/sync-shadcn-fluid-primitives.php
 * so the Powermail form styling stays in sync with the configured shadcn/create
 * preset (https://ui.shadcn.com/create) — exactly like the Component atoms.
 *
 * Edit the markup here and re-run the sync; never hand-edit the generated files
 * under Resources/Private/Extensions/Powermail (ComponentStructureTest enforces this).
 *
 * Preset-dependent values are injected as tokens:
 *   {{INPUT}}         text input recipe (from the shadcn `input` recipe)
 *   {{TEXTAREA}}      textarea recipe (from the shadcn `textarea` recipe)
 *   {{BTN_PRIMARY}}   default button (button base + variant=default + size=default)
 *   {{BTN_SECONDARY}} outline button (button base + variant=outline + size=default)
 *   {{R}}             control/surface radius token (from the `input` recipe)
 *   {{HEADER}}        the "generated" comment header
 *
 * Native <select>, checkbox, radio, file dropzone and the form surfaces are
 * Powermail-specific markup that does not map 1:1 to a registry component, so
 * they keep their semantic-token classes and only their radius follows {{R}}.
 *
 * @return array<string, string> map of repository-relative path => file content
 */
function powermailFluidTargets(array $recipes): array
{
    $radius = extractPowermailRadius($recipes['input']);

    $input = attr(normalizeClass($recipes['input'] . ' text-foreground'));
    $textarea = attr(normalizeClass($recipes['textarea'] . ' min-w-0 text-foreground'));
    $btnPrimary = attr(normalizeClass(
        $recipes['button']['base'] . ' '
        . ($recipes['button']['variants']['default'] ?? '') . ' '
        . ($recipes['button']['sizes']['default'] ?? '')
    ));
    $btnSecondary = attr(normalizeClass(
        $recipes['button']['base'] . ' '
        . ($recipes['button']['variants']['outline'] ?? '') . ' '
        . ($recipes['button']['sizes']['default'] ?? '')
    ));

    $header = "<f:comment>\n"
        . "    Generated by Build/Scripts/sync-shadcn-fluid-primitives.php (Powermail set).\n"
        . "    Edit Build/Scripts/powermail-fluid-templates.php and re-run the sync; do not hand-edit.\n"
        . "    Control and surface classes follow the configured shadcn preset recipes.\n"
        . "</f:comment>\n";

    $tokens = [
        '{{HEADER}}' => $header,
        '{{INPUT}}' => $input,
        '{{TEXTAREA}}' => $textarea,
        '{{BTN_PRIMARY}}' => $btnPrimary,
        '{{BTN_SECONDARY}}' => $btnSecondary,
        '{{R}}' => $radius,
    ];

    $base = 'Resources/Private/Extensions/Powermail/';
    $out = [];
    foreach (powermailTemplateSources() as $relativePath => $template) {
        $out[$base . $relativePath] = strtr($template, $tokens) . "\n";
    }

    return $out;
}

function extractPowermailRadius(string $inputRecipe): string
{
    if (preg_match('/(?<![\w:-])rounded-[a-z0-9-]+/', $inputRecipe, $match)) {
        return $match[0];
    }

    return 'rounded-md';
}

