    </div>

    <f:if condition="{settings.main.moresteps}">
        <div class="powermail_fieldwrap powermail_tab_navigation flex justify-between gap-2 border-t border-border pt-4">
            <f:if condition="!{iterationPages.isFirst}">
                <button type="button" class="{{BTN_SECONDARY}}" data-powermail-morestep-show="{iterationPages.index}">
                    <f:translate key="LLL:EXT:desiderio/Resources/Private/Language/powermail.xlf:powermail.multistep.previous" />
