            <f:if condition="!{iterationPages.isLast}">
                <button type="button" class="ms-auto {{BTN_PRIMARY}}" data-powermail-morestep-validate="{settings.validation.morestep.fieldset}" data-powermail-morestep-show="{iterationPages.cycle}" data-powermail-morestep-previous>
                    <f:translate key="LLL:EXT:desiderio/Resources/Private/Language/powermail.xlf:powermail.multistep.next" />
                </button>
            </f:if>
        </div>
    </f:if>
</fieldset>
