<f:form.validationResults>
    <f:if condition="{validationResults.flattenedErrors}">
        <nav class="mb-6 {{R}} border border-destructive/30 bg-destructive/10 p-4 text-sm text-destructive" aria-label="{f:translate(key: 'validationerror_container_label', extensionName: 'Powermail')}">
            <h3 class="mb-2 font-medium text-destructive"><f:translate key="validationerror_title" extensionName="Powermail" /></h3>
            <ol class="list-decimal space-y-1 ps-4">
                <f:for each="{validationResults.flattenedErrors}" as="errors">
                    <f:for each="{errors}" as="singleError">
                        <li>
                            <f:if condition="{singleError.message} == 'spam_details'">
                                <f:then>
                                    <f:translate key="validationerror_spam" extensionName="Powermail" /> {singleError.arguments.spamfactor}
                                    <f:translate key="validationerror_{singleError.message}" extensionName="Powermail">{singleError.message}</f:translate>
                                </f:then>
                                <f:else>
                                    <f:if condition="{singleError.arguments.marker}">
                                        <a class="underline underline-offset-4" href="#powermail_field_{singleError.arguments.marker}">
                                            <vh:getter.getFieldPropertyFromMarkerAndForm marker="{singleError.arguments.marker}" form="{form}" property="title" />:
                                            <f:if condition="{vh:getter.getFieldPropertyFromMarkerAndForm(marker: singleError.arguments.marker, form: form, property: 'mandatory_text')} !== ''">
                                                <f:then>{vh:getter.getFieldPropertyFromMarkerAndForm(marker: singleError.arguments.marker, form: form, property: 'mandatory_text')}</f:then>
                                                <f:else><f:translate key="validationerror_{singleError.message}" extensionName="Powermail">{singleError.message}</f:translate></f:else>
                                            </f:if>
                                        </a>
                                    </f:if>
                                </f:else>
                            </f:if>
                        </li>
                    </f:for>
                </f:for>
            </ol>
        </nav>
    </f:if>
</f:form.validationResults>
</html>
HTML;

    $sources['Templates/Form/Create.html'] = <<<'HTML'
<html
    xmlns:f="http://typo3.org/ns/TYPO3/CMS/Fluid/ViewHelpers"
    xmlns:vh="http://typo3.org/ns/In2code/Powermail/ViewHelpers"
    data-namespace-typo3-fluid="true"
>
{{HEADER}}<f:layout name="Default" />

<f:argument name="settings" type="array" optional="{true}" />
<f:argument name="mail" type="object" optional="{true}" />
<f:argument name="powermail_rte" type="string" optional="{true}" />
<f:argument name="optinActive" type="bool" optional="{true}" default="{false}" />

<f:section name="main">
    <f:alias map="{flashMessageClass: '{{R}} border border-destructive/30 bg-destructive/10 p-3 text-sm text-destructive'}">
        <f:render partial="Misc/FlashMessages" arguments="{_all}" />
    </f:alias>

    <div class="mx-auto max-w-3xl {{R}} bg-card p-6 text-card-foreground ring-1 ring-foreground/10" data-powermail-form="{mail.form.uid}">
        <f:if condition="{optinActive}">
            <f:then>
                <p class="text-sm text-muted-foreground"><f:translate key="optin_seeMail" extensionName="Powermail" /></p>
            </f:then>
            <f:else>
                <div class="prose max-w-none text-sm text-muted-foreground">
                    <vh:misc.variables mail="{mail}">
                        <f:format.html parseFuncTSPath="lib.parseFunc_RTE">{powermail_rte}</f:format.html>
                    </vh:misc.variables>
                </div>
                <f:render partial="Misc/GoogleAdwordsConversion" />
            </f:else>
        </f:if>
    </div>
</f:section>
</html>
HTML;

    $sources['Templates/Form/Form.html'] = <<<'HTML'
<html
    xmlns:f="http://typo3.org/ns/TYPO3/CMS/Fluid/ViewHelpers"
    xmlns:vh="http://typo3.org/ns/In2code/Powermail/ViewHelpers"
    data-namespace-typo3-fluid="true"
>
{{HEADER}}<f:layout name="Default" />

<f:argument name="form" type="object" optional="{true}" />
<f:argument name="settings" type="array" optional="{true}" />
<f:argument name="ttContentData" type="array" optional="{true}" />
<f:argument name="action" type="string" optional="{true}" default="create" />
<f:argument name="mail" type="object" optional="{true}" />

<f:section name="main">
    <f:alias map="{flashMessageClass: '{{R}} border border-destructive/30 bg-destructive/10 p-3 text-sm text-destructive'}">
        <f:render partial="Misc/FlashMessages" arguments="{_all}" />
    </f:alias>

    <f:if condition="{form}">
        <f:then>
            <section class="mx-auto w-full max-w-3xl">
                <f:form
                    action="{action}"
                    section="c{ttContentData.uid}"
                    name="field"
                    enctype="multipart/form-data"
                    autocomplete="{form.autocompleteToken}"
                    additionalAttributes="{vh:validation.enableJavascriptValidationAndAjax(form: form)}"
                    addQueryString="{settings.misc.addQueryString}"
                    class="powermail_form powermail_form_{form.uid} {form.css} {vh:misc.morestepClass(activate: settings.main.moresteps)} {{R}} bg-card p-4 text-card-foreground ring-1 ring-foreground/10 sm:p-6">

                    <f:if condition="{form.css} != 'nolabel'">
                        <header class="mb-6 space-y-1">
                            <h2 class="text-xl font-semibold tracking-normal text-foreground">{form.title}</h2>
                            <p class="text-sm text-muted-foreground">
                                <f:translate key="LLL:EXT:desiderio/Resources/Private/Language/powermail.xlf:powermail.form.requiredHint" />
                            </p>
                        </header>
                    </f:if>

                    <f:render partial="Misc/FormError" arguments="{_all}" />

                    <f:if condition="{settings.main.moresteps}">
                        <nav class="mb-6 grid gap-2 {{R}} border border-border bg-muted/30 p-1 text-sm sm:grid-flow-col sm:auto-cols-fr" aria-label="{f:translate(key: 'LLL:EXT:desiderio/Resources/Private/Language/powermail.xlf:powermail.multistep.label')}">
                            <f:for each="{form.pages}" as="page" iteration="iterationPages">
                                <button class="inline-flex h-8 items-center justify-center {{R}} px-3 text-xs font-medium text-muted-foreground transition-colors outline-none hover:bg-background hover:text-foreground focus-visible:ring-1 focus-visible:ring-ring/50 data-[active=true]:bg-background data-[active=true]:text-foreground data-[active=true]:ring-1 data-[active=true]:ring-foreground/10"
                                        type="button"
                                        data-active="{f:if(condition: iterationPages.isFirst, then: 'true', else: 'false')}"
                                        data-powermail-morestep-validate="{settings.validation.morestep.fieldset}"
                                        data-powermail-fieldset="{page.uid}"
                                        data-powermail-morestep-current="{iterationPages.index}"
                                        data-powermail-morestep-show="{iterationPages.index}">
                                    <span class="me-2 inline-flex size-5 items-center justify-center {{R}} border border-border bg-muted text-[11px]">{iterationPages.cycle}</span>
                                    {page.title}
                                </button>
                            </f:for>
                        </nav>
                    </f:if>

                    <div class="space-y-6">
                        <f:for each="{form.pages}" as="page" iteration="iterationPages">
                            <f:render partial="Form/Page" arguments="{_all}" />
                        </f:for>
                    </div>

                    <f:form.hidden name="mail[form]" value="{form.uid}" class="powermail_form_uid" respectSubmittedDataValue="false" />
                    <f:render partial="Misc/HoneyPod" arguments="{form: form}" />
                </f:form>
            </section>
        </f:then>
        <f:else>
            <div class="{{R}} border border-destructive/30 bg-destructive/10 p-4 text-sm text-destructive">
                <f:translate key="error_no_form" extensionName="Powermail" />
            </div>
        </f:else>
    </f:if>
</f:section>
</html>
HTML;

    $sources['Templates/Form/Confirmation.html'] = <<<'HTML'
<html
    xmlns:f="http://typo3.org/ns/TYPO3/CMS/Fluid/ViewHelpers"
    xmlns:vh="http://typo3.org/ns/In2code/Powermail/ViewHelpers"
    data-namespace-typo3-fluid="true"
>
{{HEADER}}<f:layout name="Default" />

<f:argument name="settings" type="array" optional="{true}" />
<f:argument name="mail" type="object" optional="{true}" />
<f:argument name="powermail_all" type="string" optional="{true}" />
<f:argument name="ttContentData" type="array" optional="{true}" />

<f:section name="main">
    <div class="mx-auto max-w-3xl {{R}} bg-card p-6 text-card-foreground ring-1 ring-foreground/10">
        <div class="mb-6 space-y-1">
            <h2 class="text-xl font-semibold tracking-normal text-foreground">
                <f:translate key="LLL:EXT:desiderio/Resources/Private/Language/powermail.xlf:powermail.confirmation.title" />
            </h2>
            <p class="text-sm text-muted-foreground">
                <f:translate key="LLL:EXT:desiderio/Resources/Private/Language/powermail.xlf:powermail.confirmation.description" />
            </p>
        </div>
        <div class="{{R}} border border-border bg-muted/30 p-4 text-sm text-muted-foreground">
            {powermail_all -> f:format.raw()}
        </div>
        <div class="mt-6 flex flex-wrap gap-2">
            <f:form
                action="form"
                section="c{ttContentData.uid}"
                name="field"
                enctype="multipart/form-data"
                addQueryString="{settings.misc.addQueryString}"
                additionalAttributes="{vh:validation.enableJavascriptValidationAndAjax(form: mail.form)}">
                <f:render section="HiddenFields" arguments="{_all}" />
                <f:form.submit
                    value="{f:translate(key: 'confirmation_prev', extensionName: 'Powermail')}"
                    additionalAttributes="{data-powermail-form-ajax: 'confirmation'}"
                    class="{{BTN_SECONDARY}}" />
            </f:form>

            <f:form
                action="create"
                section="c{ttContentData.uid}"
                name="field"
                enctype="multipart/form-data"
                addQueryString="{settings.misc.addQueryString}"
                additionalAttributes="{vh:validation.enableJavascriptValidationAndAjax(form: mail.form)}">
                <f:render section="HiddenFields" arguments="{_all}" />
                <f:form.submit
                    value="{f:translate(key: 'confirmation_submit', extensionName: 'Powermail')}"
                    additionalAttributes="{data-powermail-form-ajax: 'submit'}"
                    class="{{BTN_PRIMARY}}" />
            </f:form>
        </div>
    </div>
</f:section>

<f:section name="HiddenFields">
    <f:for each="{mail.answers}" as="answer">
        <f:if condition="{vh:condition.isArray(val: answer.value)}">
            <f:then>
                <f:for each="{answer.value}" as="subvalue" iteration="i">
                    <f:form.hidden property="{answer.field.marker}.{i.index}" value="{subvalue}" respectSubmittedDataValue="false" />
                </f:for>
            </f:then>
            <f:else>
                <f:form.hidden property="{answer.field.marker}" value="{answer.value}" respectSubmittedDataValue="false" />
            </f:else>
        </f:if>
    </f:for>
    <f:form.hidden name="mail[form]" value="{mail.form.uid}" class="powermail_form_uid" />
</f:section>
</html>
HTML;

    return $sources;
}
